"use client";

import Link from "next/link";

export default function AdminDashboard() {
  const adminMenus = [
    { title: "회원 관리", path: "/admin/member", icon: "👤" },
    { title: "게시물 관리", path: "/admin/board", icon: "📝" },
    { title: "일반의약품 관리", path: "/admin/druggen", icon: "💊" },
    { title: "전문의약품 동기화", path: "/admin/drugpro", icon: "💉" },
    { title: "약국목록 동기화", path: "/admin/pharmacy", icon: "🏥" },
  ];

  return (
    <div>
      <div className="write-header" style={{ borderBottom: 'none', marginBottom: '0' }}>
        <h1 className="admin-title">관리자 대시보드</h1>
        <p className="write-subtitle">서비스의 주요 데이터를 한눈에 관리하세요.</p>
      </div>
      
      <div className="dashboard-grid">
        {/* 메뉴 카드 반복 렌더링 */}
        {adminMenus.map((menu, index) => (
          <Link href={menu.path} key={index} className="dashboard-card">
            <span className="card-icon">{menu.icon}</span>
            <span className="card-title">{menu.title}</span>
          </Link>
        ))}

        {/* 6번째 빈 칸 */}
        <div className="dashboard-card empty-card">
          <span className="card-icon" style={{ opacity: 0.3 }}>+</span>
          <span className="card-title" style={{ color: '#aaa' }}>준비 중</span>
        </div>
      </div>
    </div>
  );
}